module RefModule (
	input clk,
	input we,
	input [3:0] read_addr,
	input [3:0] write_addr,
	input [7:0] din,
	output reg [7:0] dout);
  wire _tap_clk = clk & {1{1'b1}};


	reg [7:0] mem [15:0];

	always @(posedge clk) begin
		if (we)
			mem[write_addr] <= din;
		dout <= mem[read_addr];
	end
endmodule
